    requestId,
    type: "audit-export-ready",
    customerVisible: true,
    payload: auditPayload,
    hash: createHash("sha256").update(JSON.stringify(auditPayload)).digest("hex"),
    createdAt: now
  });

  return buildPortalView(db);
}
