import { withDb } from "./db.mjs";
import { RULES, qualifies, ownersOf, signalsOf } from "./derive.mjs";

const QUALIFYING_MESSAGE = "We are coordinating executive recovery for your delayed shipment.";
const MONITORING_MESSAGE =
  "We are continuing standard monitoring for your account and will notify you if anything changes.";

export async function run(now = "2026-06-18T12:00:00.000Z") {
  return withDb(async (db) => {
    const account = await db.collection("accounts").findOne({});
    if (!account) {
      throw new Error("No account found in live database");
    }

    const facts = {
      account,
      invoices: Array.isArray(account.invoices) ? account.invoices : [],
      shipments: Array.isArray(account.shipments) ? account.shipments : [],
      regulatoryFlags: Array.isArray(account.regulatoryFlags) ? account.regulatoryFlags : [],
      supportCases: Array.isArray(account.supportCases) ? account.supportCases : [],
      usage: account.usage ?? {}
    };

    const signalNames = signalsOf(facts, now);
    const isQualifying = qualifies(facts, now);
    const ownerGroups = isQualifying ? ownersOf(facts, now) : [];
    const status = isQualifying ? RULES.escalationStatus : RULES.monitorStatus;
    const riskSummary = `${signalNames.length} signals: ${signalNames.join(", ")}`;
    const nextStep = isQualifying
      ? `${ownerGroups[0]} recovery review by 16:00`
      : "Continue standard monitoring.";
    const customerMessage = isQualifying ? QUALIFYING_MESSAGE : MONITORING_MESSAGE;
    const dueAt = buildDueAt(now);

    await replaceCollection(db.collection("workflow_state"), [
      {
        account_id: account._id,
        accountId: account._id,
        account_name: account.name,
        accountName: account.name,
        status,
        next_step: nextStep,
        nextStep,
        risk_summary: riskSummary,
        riskSummary,
        updated_at: now,
        updatedAt: now
      }
    ]);

    await replaceCollection(
      db.collection("owner_tasks"),
      ownerGroups.map((ownerGroup) => ({
        account_id: account._id,
        accountId: account._id,
        owner_group: ownerGroup,
        ownerGroup,
        title: taskTitle(ownerGroup),
        due_at: dueAt,
        dueAt,
        status: "open",
        created_at: now,
        createdAt: now
      }))
    );

    await replaceCollection(db.collection("customer_messages"), [
      {
        account_id: account._id,
        accountId: account._id,
        body: customerMessage,
        customer_visible: true,
        customerVisible: true,
        status: "sent",
        created_at: now,
        createdAt: now
      }
    ]);

    await replaceCollection(db.collection("audit_events"), [
      {
        account_id: account._id,
        accountId: account._id,
        body: customerMessage,
        summary: customerMessage,
        type: "workflow_update",
        customer_visible: true,
        customerVisible: true,
        status: "published",
        created_at: now,
        createdAt: now
      }
    ]);

    return { status, ownerGroups, riskSummary };
  });
}

function buildDueAt(now) {
  const due = new Date(now);
  due.setUTCHours(16, 0, 0, 0);
  return due.toISOString();
}

function taskTitle(ownerGroup) {
  return {
    "Customer Success": "Coordinate executive recovery plan",
    Legal: "Review regulated shipment and disclosure language",
    Finance: "Resolve payment hold and invoice risk",
    Support: "Publish customer-safe support timeline"
  }[ownerGroup] || `Follow up for ${ownerGroup}`;
}

async function replaceCollection(collection, docs) {
  await collection.deleteMany({});
  if (docs.length > 0) {
    await collection.insertMany(docs);
  }
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run()
    .then(() => console.log("workflow done"))
    .catch((error) => {
      console.error(error);
      process.exit(1);
    });
}

